insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:1-6-business-growth:mcq:868e7732', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "A business increasing its market share would normally lead to the business having:", "options": ["More customers", "A better reputation", "A guarantee of supplies", "A better workforce"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A — More customers. Market share measures the proportion of total market sales held by the business. If market share increases, the business holds a larger slice of the market, which means more customers relative to rivals. The other options are not direct consequences of increased market share."}'::jsonb),
('business:1-6-business-growth:mcq:4fbd43d2', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "A forwards vertical merger is when:", "options": ["A business merges with another similar business", "A business merges with a supplier", "A business merges with a business it supplies goods to", "A business merges with a totally different business"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — A business merges with a business it supplies goods to. Forward vertical = moving forward down the supply chain towards the customer. A: Merging with a similar business is horizontal. B: Merging with a supplier is backward vertical. D: Merging with a totally different business is diversification."}'::jsonb),
('business:1-6-business-growth:mcq:6ac4ba0f', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "A takeover is when:", "options": ["A business agrees to join with another business", "A business buys more than 50% of another business", "A business buys any share of another business", "A business takes over paying the workers at another business"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — A business buys more than 50% of another business. Owning more than 50% gives a controlling interest — the buyer can outvote all other shareholders on key decisions. A: Agreeing to join is a merger. C: Buying any share does not give control. D: This is not a business growth concept."}'::jsonb),
('business:1-6-business-growth:mcq:3b322834', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "Which of the following describes a takeover?", "options": ["Orange and T-Mobile joined together to become EE", "Disney the film-maker bought the animation company Pixar", "Honda Motor Company builds a factory to manufacture gear boxes for its cars", "Netflix increases its share of the market"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — Disney buying Pixar. A takeover is when one business purchases a controlling interest in another. Disney acquired (bought) Pixar. A: Orange and T-Mobile agreed to join — that is a merger. C: Building a new factory is organic growth (increasing capacity internally). D: Netflix growing market share organically is organic growth."}'::jsonb),
('business:1-6-business-growth:mcq:ac9fe9a0', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT a method of external growth?", "options": ["Horizontal merger", "Backward vertical takeover", "Developing a new product range", "Diversification"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — Developing a new product range. Developing new products internally is a method of organic (internal) growth. Options A, B, and D all involve joining with or buying another business, making them forms of external growth."}'::jsonb),
('business:1-6-business-growth:mcq:a975aa77', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "A business assembling computers merges with a microchip supplier. This is an example of:", "options": ["Horizontal growth", "Backward vertical growth", "Forward vertical growth", "Diversification"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — Backward vertical growth. The computer assembler is buying its supplier (the microchip company), moving backwards up the supply chain. A: Horizontal would mean both do the same thing. C: Forward vertical would be buying a retailer that sells the computers. D: Diversification would mean an entirely unrelated industry."}'::jsonb),
('business:1-6-business-growth:tf:4a2ae400', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "Organic growth in a business is about growing vegetables organically."}'::jsonb, '{"answer": false, "explain": "FALSE. Organic growth means the internal growth of a business — growing from within by increasing sales, developing products, or gaining customers. The word ''organic'' here means ''natural/internal'', not agricultural."}'::jsonb),
('business:1-6-business-growth:tf:4f6d85a6', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "More effective marketing will help a business grow."}'::jsonb, '{"answer": true, "explain": "TRUE. Better marketing attracts new customers and increases sales — a classic method of organic growth. It helps the business grow revenue and potentially its market share."}'::jsonb),
('business:1-6-business-growth:tf:864ce7b5', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "Market share is the share a worker has in the business."}'::jsonb, '{"answer": false, "explain": "FALSE. Market share is the proportion of total market sales held by one business, expressed as a percentage. It has nothing to do with employees. A ''share'' in a company is a unit of ownership — a completely different concept."}'::jsonb),
('business:1-6-business-growth:tf:871a1803', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "A merger is when one business buys a controlling interest in another business."}'::jsonb, '{"answer": false, "explain": "FALSE. A merger is when two businesses mutually agree to join together. When one business purchases a controlling interest (over 50% of shares), that is a takeover. The key difference is mutual agreement vs one business buying control."}'::jsonb),
('business:1-6-business-growth:tf:4bfca884', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "With a 30% increase in the total market, a business that increases its sales by 20% will have increased its market share."}'::jsonb, '{"answer": false, "explain": "FALSE. Market share is relative to the total market. If the total market grew by 30% but the business only grew by 20%, the business''s market share has actually decreased — it is growing more slowly than the market overall."}'::jsonb),
('business:1-6-business-growth:tf:cc16e37f', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "External growth is always a better method of growth than organic growth."}'::jsonb, '{"answer": false, "explain": "FALSE. Whether external or organic growth is better depends entirely on the context. External growth is faster but more expensive and risky. Organic growth is slower but cheaper and retains owner control. The best method depends on the business''s objectives, finances, and the competitiveness of its market."}'::jsonb),
('business:1-6-business-growth:tf:e4290dde', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "A backward vertical takeover involves a business buying a company it sells its products to."}'::jsonb, '{"answer": false, "explain": "FALSE. Backward vertical means buying a supplier — a business that provides goods or services to you. Buying a business you sell to is forward vertical growth. Remember: backward = moving back up the supply chain towards suppliers."}'::jsonb),
('business:1-6-business-growth:tf:1c912ce0', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "Horizontal growth occurs when two businesses at the same stage of production in the same industry combine."}'::jsonb, '{"answer": true, "explain": "TRUE. Horizontal growth is exactly this — two businesses doing the same thing joining together, whether as a merger or takeover. Examples: two competing supermarkets merging, or two rival car wash businesses."}'::jsonb),
('business:1-6-business-growth:tf:b4c2329f', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "Organic growth is less risky than external growth."}'::jsonb, '{"answer": true, "explain": "TRUE. Organic growth uses internal resources and grows at a manageable pace, reducing financial risk. External growth involves large upfront costs, potential management difficulties, and culture clashes — making it inherently riskier."}'::jsonb),
('business:1-6-business-growth:tf:230fb5d9', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "A takeover requires a business to buy more than 50% of the shares in another business to gain a controlling interest."}'::jsonb, '{"answer": true, "explain": "TRUE. Owning more than 50% means the buyer can outvote all other shareholders on any decision, giving it full control over the business''s direction and strategy."}'::jsonb),
('business:1-6-business-growth:tf:2d762a20', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "Diversification involves a business merging with a direct competitor in the same industry."}'::jsonb, '{"answer": false, "explain": "FALSE. Diversification is when a business joins with a company in a completely different, unrelated industry. Joining with a direct competitor would be horizontal growth — they are in the same market."}'::jsonb),
('business:1-6-business-growth:tf:5d6b3d1a', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "It is important for technology-based businesses to constantly bring out new products if they are to grow."}'::jsonb, '{"answer": true, "explain": "TRUE. In the technology sector, products quickly become outdated. Businesses like Apple rely on constant research and development (e.g. new iPhone models each year) to stay competitive and continue growing organically through product development."}'::jsonb),
('business:1-6-business-growth:learn:fd192647', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>This sub-topic covers the ways in which a business can increase in size — either by growing from within (<strong>organic/internal growth</strong>) or by joining with or buying other businesses (<strong>external growth</strong>).</p>\n<ul>\n  <li><strong>Organic Growth:</strong> Concerned with the <em>internal</em> growth of a business, e.g. by increasing sales, developing new products, or gaining new customers — without joining with another business.</li>\n  <li><strong>External Growth:</strong> The growth of a business by <em>takeover or merger</em> with another business.</li>\n  <li><strong>Merger:</strong> Where two or more businesses <em>mutually agree</em> to join together to become one new business.</li>\n  <li><strong>Takeover:</strong> Where a business takes a <em>controlling interest</em> in another business, for example by buying more than 50% of the shares in it.</li>\n  <li><strong>Horizontal Growth:</strong> A merger or takeover where the two businesses are involved in a <em>similar operation at the same stage of production</em> in the same industry.</li>\n  <li><strong>Backward Vertical Growth:</strong> When a business merges with, or takes over, a business that <em>supplies</em> it with goods or services — moving back up the supply chain.</li>\n  <li><strong>Forward Vertical Growth:</strong> When a business merges with, or takes over, a business that it <em>supplies goods or services to</em> — moving forward down the supply chain.</li>\n  <li><strong>Diversification:</strong> When a business merges with or takes over another business with which it has <em>no connection</em> — entering a completely new market.</li>\n  <li><strong>Market Share:</strong> A business''s sales as a percentage of total market sales. Formula: (Business Sales ÷ Total Market Sales) × 100.</li>\n</ul>", "question": "A business merges with a company in a completely unrelated industry, such as a clothing brand buying a software firm. What type of growth is this?", "options": ["Diversification", "Horizontal growth", "Backward vertical growth", "Forward vertical growth"]}'::jsonb, '{"answer": 0, "explain": "Diversification is defined as merging with or taking over a business with no connection, entering a completely new market."}'::jsonb),
('business:1-6-business-growth:learn:5cbd5ed6', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'learn', 'mcq', 1, '{"readingTitle": "Organic (Internal) Growth — Methods", "reading": "<p><strong>Organic growth</strong> means expanding using the business''s own internal resources and capabilities, without merging with or acquiring another business. It is generally a slower but safer form of growth.</p>\n<ul>\n  <li><strong>Increasing Output:</strong> The business produces more — by using resources more efficiently, using spare capacity, or building new factories and expanding premises.</li>\n  <li><strong>Developing New Products:</strong> The business researches and develops new products, buys ideas/licences from others, or copies successful concepts from competitors. Technology businesses like Apple rely heavily on this.</li>\n  <li><strong>Gaining New Customers:</strong> The business attracts customers it did not previously have by reducing prices, opening new shops, or investing in better marketing and advertising.</li>\n  <li><strong>Increasing Market Share:</strong> The business wins a larger proportion of total market sales from rivals through better pricing, quality, or marketing.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Pets at Home</h4>\n  <p>Pets at Home achieved organic growth by <strong>expanding the range of services it offers internally</strong> — including grooming services and veterinary services. Rather than buying other businesses, it grew by developing new revenue streams within its existing brand and customer base, attracting new customer segments who need pet care beyond just products.</p>\n  <p><strong>Takeaway:</strong> Adding new services to an existing customer base is a classic method of organic growth — no mergers required.</p>\n</div>", "question": "Which of the following is an example of organic (internal) growth?", "options": ["A business develops a new product via its own research", "A business buys a controlling stake in a rival firm", "Two businesses agree to merge into one new company", "A business takes over its main supplier"]}'::jsonb, '{"answer": 0, "explain": "Organic growth expands the business using its own internal resources, such as developing new products, without merging with or acquiring another business."}'::jsonb),
('business:1-6-business-growth:learn:c0cbf42b', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'learn', 'mcq', 1, '{"readingTitle": "External (Inorganic) Growth — Mergers & Takeovers", "reading": "<p><strong>External growth</strong> happens when a business joins with or buys another business. It is a faster way to grow but carries higher risk and cost.</p>\n<ul>\n  <li><strong>Merger:</strong> Two businesses <em>mutually agree</em> to combine and form one new business. Neither forces the other. Example: Orange + T-Mobile agreeing to form EE.</li>\n  <li><strong>Takeover (Acquisition):</strong> One business <em>buys a controlling stake</em> (over 50% of shares) in another, often without the target having a choice. Example: Disney buying Pixar.</li>\n</ul>\n<p><strong>Key difference:</strong> A merger is by <strong>mutual agreement</strong>; a takeover is where one business gains <strong>control</strong> over another by purchasing shares.</p>\n<div class=\"formula-box\">\n  <strong>Supply Chain Direction (Memory Aid):</strong><br>\n  Supplier &rarr; Manufacturer &rarr; Retailer &rarr; Customer<br>\n  <strong>Backward vertical</strong> = buying your supplier (moving ← left)<br>\n  <strong>Forward vertical</strong> = buying your retailer/customer (moving → right)<br>\n  <strong>Horizontal</strong> = buying a business at the same level as you<br>\n  <strong>Diversification</strong> = buying a business in a completely unrelated industry\n</div>", "question": "What is the key difference between a merger and a takeover?", "options": ["A merger is mutual agreement; a takeover is buying a controlling stake", "A merger only happens between competitors, while a takeover only happens between suppliers", "A merger is always cheaper than a takeover", "A takeover always results in a completely new company name being formed"]}'::jsonb, '{"answer": 0, "explain": "A merger is by mutual agreement, whereas a takeover is where one business gains control by purchasing over 50% of another''s shares, often without the target having a choice."}'::jsonb),
('business:1-6-business-growth:learn:73da6118', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'learn', 'mcq', 1, '{"readingTitle": "Types of External Growth", "reading": "<p>External growth can take several forms depending on the <strong>relationship between the two businesses</strong> involved:</p>\n<ul>\n  <li><strong>Horizontal Growth:</strong> Two businesses at the <em>same stage of production in the same industry</em> join together. Example: A business making radios merges with a business making televisions. Example: Two rival restaurant chains merging.</li>\n  <li><strong>Backward Vertical Growth:</strong> A business joins with a <em>supplier</em>. Example: A computer assembler merges with a microchip supplier. Example: A jam manufacturer buys a fruit farm.</li>\n  <li><strong>Forward Vertical Growth:</strong> A business joins with a business it <em>sells to</em>. Example: A pottery maker takes over a pottery shop. Example: Greggs merging with a sandwich retailer.</li>\n  <li><strong>Diversification:</strong> A business joins a company in a <em>completely different, unrelated industry</em>. Example: A clothing company buying a software firm.</li>\n</ul>\n<p>The table below shows key examples to help you remember:</p>\n<ul>\n  <li>Jam maker + fruit farm = <strong>Backward vertical</strong> (farm supplies fruit)</li>\n  <li>Potter + pottery shop = <strong>Forward vertical</strong> (shop sells the pottery)</li>\n  <li>Radio maker + TV maker = <strong>Horizontal</strong> (same industry, same stage)</li>\n  <li>Clothing brand + tech firm = <strong>Diversification</strong> (no connection)</li>\n</ul>", "question": "A potter (pottery maker) takes over the shop that sells its pottery to customers. What type of external growth is this?", "options": ["Forward vertical growth", "Backward vertical growth", "Horizontal growth", "Diversification"]}'::jsonb, '{"answer": 0, "explain": "Forward vertical growth occurs when a business joins with a business it sells to — here the potter joins the shop it supplies pottery to, moving forward down the supply chain."}'::jsonb),
('business:1-6-business-growth:learn:b36eb43c', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'learn', 'mcq', 1, '{"readingTitle": "Advantages & Disadvantages: Organic vs External Growth", "reading": "<p>Both forms of growth have clear benefits and drawbacks. In the exam you may be asked to <strong>analyse</strong> or <strong>evaluate</strong> which method is more appropriate for a specific business.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages of Organic Growth</div>\n    <div class=\"pro-item\"><strong>Less risky:</strong> The business grows at a pace it can manage, reducing the chance of financial overextension.</div>\n    <div class=\"pro-item\"><strong>Maintains control:</strong> Owners retain full strategic control and decision-making authority — profits do not need to be shared with new partners.</div>\n    <div class=\"pro-item\"><strong>Builds own expertise:</strong> The business develops its own skills and brand identity, leading to a stronger competitive position over time.</div>\n    <div class=\"pro-item\"><strong>Lower cost:</strong> Funded through internal funds (retained profit), avoiding the large upfront costs of buying another business.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages of Organic Growth</div>\n    <div class=\"con-item\"><strong>Slow:</strong> Takes much longer to achieve significant growth — shareholders may prefer faster expansion to boost returns more quickly.</div>\n    <div class=\"con-item\"><strong>Limited growth potential:</strong> In a competitive or saturated market there may be a ceiling to how much the business can grow from within.</div>\n    <div class=\"con-item\"><strong>Competitors may overtake:</strong> Rivals using external growth can gain market share far more rapidly, potentially leaving organic growers behind.</div>\n  </div>\n</div>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages of External Growth</div>\n    <div class=\"pro-item\"><strong>Fast:</strong> Market share and revenue can increase almost immediately, satisfying impatient shareholders and investors.</div>\n    <div class=\"pro-item\"><strong>Reduces competition:</strong> Taking over or merging with a rival removes a competitor from the market — potentially allowing higher prices.</div>\n    <div class=\"pro-item\"><strong>Access to expertise:</strong> The business instantly gains the skills, technology, customer base and reputation of the acquired business.</div>\n    <div class=\"pro-item\"><strong>Economies of scale:</strong> A larger combined business can negotiate bulk discounts, spread fixed costs, and lower unit costs.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages of External Growth</div>\n    <div class=\"con-item\"><strong>Very expensive:</strong> Buying another business requires significant investment or borrowing, greatly increasing financial risk.</div>\n    <div class=\"con-item\"><strong>Loss of control:</strong> In a merger, profits and decisions must be shared with other owners — disagreements and conflict can arise.</div>\n    <div class=\"con-item\"><strong>Management challenges:</strong> Managers may lack the experience to run a much larger, more complex organisation, leading to inefficiency and wasted money.</div>\n    <div class=\"con-item\"><strong>Culture clashes:</strong> Employees from different businesses may have conflicting values or working practices, reducing productivity.</div>\n  </div>\n</div>", "question": "Which of these is listed as a key advantage of organic growth over external growth?", "options": ["Owners maintain full strategic control without having to share profits", "Market share increases almost immediately", "The business gains instant access to a rival''s expertise and customer base", "Competition in the market is reduced"]}'::jsonb, '{"answer": 0, "explain": "The card lists ''maintains control'' as an advantage of organic growth, since owners retain full decision-making authority; the other options are listed as advantages of external growth instead."}'::jsonb),
('business:1-6-business-growth:learn:ad820f53', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'learn', 'mcq', 1, '{"readingTitle": "Market Share — Formula & Calculations", "reading": "<p>Market share measures a business''s dominance within its market. Increasing market share means the business is winning customers from rivals, even if the overall market is growing.</p>\n<div class=\"formula-box\">\n  <strong>Market Share (%) =</strong> (Sales of the business ÷ Total sales in the market) &times; 100\n</div>\n<p><strong>Worked Example (Shinz Ltd):</strong><br>\nThe car washing market in Littlelong = £460,000.<br>\nShinz Ltd holds 40% market share.<br>\nValue = 40% &times; £460,000 = <strong>£184,000</strong></p>\n<p><strong>Worked Example (Combined merger):</strong><br>\nShinz Ltd (40%) + Littlelong Motors (10%) = <strong>50% combined = £230,000</strong></p>\n<p><strong>Key warning:</strong> If the total market grows by 30% but a business''s sales only grow by 20%, that business''s market share has actually <em>fallen</em> — even though its sales went up. Market share is always relative to the total market.</p>\n<ul>\n  <li>Market share rises → more competitive, greater pricing power, stronger negotiating position with suppliers.</li>\n  <li>Market share falls → rivals growing faster, business losing ground even if its own sales are rising.</li>\n</ul>", "question": "A business''s sales grow by 20% while the total market grows by 30% over the same period. What happens to the business''s market share?", "options": ["It falls, since market share is relative to the market", "It rises, because the business''s sales increased", "It stays exactly the same", "It cannot be determined without knowing profit figures"]}'::jsonb, '{"answer": 0, "explain": "The card''s key warning states that if total market sales grow faster than a business''s own sales, its market share falls even though its sales have risen, because market share is always relative to the total market."}'::jsonb),
('business:1-6-business-growth:learn:42784fcb', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'learn', 'mcq', 1, '{"readingTitle": "Real-World Case Studies in Business Growth", "reading": "<div class=\"case-study-box\">\n  <h4>Case Study: Apple — Organic Growth</h4>\n  <p>Apple was started in 1976 and has grown to become the largest company in the world — almost entirely through <strong>organic growth</strong>. Rather than buying many other businesses, Apple focused on researching and developing its own products: the MacBook Pro, iPhone, iPad, and Apple Pay. Apple has taken over only a very small number of businesses in its entire history.</p>\n  <p>Apple also invested heavily in innovative marketing — introducing new products around September each year, using catchy music and minimalistic advertising to build a powerful global brand. Revenue grew from $33,300 in 1976 to $49.6 billion in 2016.</p>\n  <p><strong>Takeaway:</strong> Organic growth through product innovation and brand-building allowed Apple to maintain complete strategic control, resulting in one of the world''s most profitable companies without relying on expensive acquisitions.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Boohoo — External Growth</h4>\n  <p>Boohoo started in 2006 as an online fashion retailer targeting 16–24 year olds and initially grew organically via social media and website development. However, in 2020/2021 it shifted to <strong>external growth</strong>, acquiring well-known brands including Debenhams, Oasis, Burton, and Dorothy Perkins. This instantly gave Boohoo access to millions of customers across different demographics.</p>\n  <p>However, taking on so many businesses simultaneously created significant management challenges — controlling a much larger organisation increased costs and risked reducing overall efficiency and profitability.</p>\n  <p><strong>Takeaway:</strong> External growth gave Boohoo rapid access to new markets, but managing multiple acquisitions simultaneously increased the risk of losing control and damaging the original brand.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Greggs — Choosing Between Growth Methods</h4>\n  <p>Greggs is a ''food-on-the-go'' brand with 20,000 employees and a growing vegan product range (vegan sausage rolls launched 2019 boosted sales by 9.6% in 7 weeks). Greggs considered two external growth options: (1) a <strong>backward vertical merger</strong> with a flour producer to secure raw material supply and reduce costs; (2) a <strong>horizontal takeover</strong> of a rival food-on-the-go brand to eliminate competition and rapidly increase market share.</p>\n  <p><strong>Takeaway:</strong> Different growth strategies serve different purposes. Backward vertical growth secures supplies and cuts costs; horizontal takeover removes competition and boosts market share rapidly. The best choice depends on the business''s specific aims and context.</p>\n</div>", "question": "Which case study business grew almost entirely through organic growth, taking over only a very small number of businesses in its history?", "options": ["Apple", "Boohoo", "Greggs", "None of these — all three grew solely through mergers"]}'::jsonb, '{"answer": 0, "explain": "The card states Apple grew to become the largest company in the world almost entirely through organic growth, focusing on researching and developing its own products rather than buying other businesses."}'::jsonb),
('business:1-6-business-growth:misc:2176ee6c', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students describe organic growth as simply ''growing your business naturally'' without specifying a method.</p><p><strong>✅ The correct idea:</strong> Organic growth has specific methods: increasing output, developing new products, gaining new customers, and increasing market share. Always name the specific method and explain how it works in the context of the business.</p>", "question": "What does an examiner expect a student to do when answering a question on organic growth, rather than just saying it means ''growing naturally''?", "options": ["Name the specific method, e.g. new products", "Just state that the business is getting bigger", "Compare it to a takeover", "Give the exact date the business started"]}'::jsonb, '{"answer": 0, "explain": "Organic growth has specific named methods that must be identified and explained in context, not just described vaguely as ''growing naturally''."}'::jsonb),
('business:1-6-business-growth:misc:920ebd06', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students confuse mergers and takeovers and use the terms interchangeably.</p><p><strong>✅ The correct idea:</strong> A merger is by mutual agreement — both businesses choose to join. A takeover is when one business buys more than 50% of another''s shares to gain control — the target may not have wanted this. The examiner will penalise you for using these interchangeably.</p>", "question": "How does a takeover differ from a merger?", "options": ["A takeover is buying over 50% of shares to gain control", "A takeover and a merger are simply two names for the same process", "A takeover always involves two businesses of equal size", "A takeover requires both businesses to rebrand under a new name"]}'::jsonb, '{"answer": 0, "explain": "A merger is by mutual agreement, while a takeover is when one business buys a controlling stake (over 50% of shares) — using the terms interchangeably will be penalised."}'::jsonb),
('business:1-6-business-growth:misc:e3b7468f', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students say a jam maker buying a fruit farm is horizontal growth because both involve food.</p><p><strong>✅ The correct idea:</strong> Horizontal growth means SAME stage of production in the SAME industry. A jam maker and a fruit farm are at DIFFERENT stages — one supplies the other. This is BACKWARD VERTICAL growth. Think about the supply chain direction.</p>", "question": "A jam manufacturer buys a fruit farm that supplies it with fruit. What type of growth is this?", "options": ["Backward vertical growth, since the farm supplies the jam factory", "Horizontal growth, because both businesses are involved with food", "Forward vertical growth, because the farm sells its fruit onward", "Diversification, because farming and manufacturing are different activities"]}'::jsonb, '{"answer": 0, "explain": "This is backward vertical growth, not horizontal growth, because the farm supplies the jam maker — they are at different stages of production, not the same stage in the same industry."}'::jsonb),
('business:1-6-business-growth:misc:5474f79d', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students describe all external growth as ''diversification''.</p><p><strong>✅ The correct idea:</strong> Diversification is specifically when a business joins with a company in a completely UNRELATED industry. If the businesses are connected by the supply chain or operate in the same industry, it is horizontal or vertical, NOT diversification.</p>", "question": "Which best describes when a business merger or takeover counts as ''diversification''?", "options": ["Only when joining a totally unrelated industry", "Whenever any external growth takes place", "Whenever a business merges with a supplier", "Whenever a business takes over a competitor"]}'::jsonb, '{"answer": 0, "explain": "Diversification specifically means joining an unrelated industry — if the businesses are linked through the supply chain or same industry, it is vertical or horizontal growth instead, not diversification."}'::jsonb),
('business:1-6-business-growth:misc:6475d6b5', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students write ''this will lead to more profit'' as their analysis mark.</p><p><strong>✅ The correct idea:</strong> Examiners will not award analysis marks for just saying ''more profit''. You must explain the chain: WHY does the action lead to more profit? e.g., ''Reducing competition means fewer alternatives for customers, allowing the business to charge higher prices, increasing its profit margin (AN).''</p>", "question": "Why would an exam answer that simply states ''this will lead to more profit'' fail to earn an analysis mark?", "options": ["Because it skips the chain of reasoning explaining why", "Because ''profit'' is spelled incorrectly in most answers", "Because analysis marks are only for evaluation questions", "Because profit is not a valid business impact"]}'::jsonb, '{"answer": 0, "explain": "Examiners require the full chain of reasoning (e.g. reduced competition allows higher prices, increasing profit margin) rather than a bare assertion of ''more profit''."}'::jsonb),
('business:1-6-business-growth:misc:d759b2a5', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think increasing market share always means a business''s sales have increased.</p><p><strong>✅ The correct idea:</strong> Market share can increase even if the business''s sales stay the same — if the total market shrank. Sales can also rise while market share falls if the total market grew faster. Market share is ALWAYS relative to total market size.</p>", "question": "Can a business''s sales rise while its market share falls at the same time?", "options": ["Yes, if the total market grows faster than its own sales", "No, market share and sales always move in the same direction", "No, market share can only be calculated using profit figures", "Yes, but only if the business changes its prices"]}'::jsonb, '{"answer": 0, "explain": "Market share is always relative to total market size, so sales can rise while market share falls if the overall market is growing even faster."}'::jsonb),
('business:1-6-business-growth:misc:589f52da', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think organic growth and internal growth are different terms.</p><p><strong>✅ The correct idea:</strong> Organic growth and internal growth are the same thing — both refer to growing the business from within, without joining with another business. These terms are completely interchangeable in the exam.</p>", "question": "Are ''organic growth'' and ''internal growth'' different concepts in the exam?", "options": ["No, they are interchangeable terms for growing from within", "Yes, organic growth only applies to product development", "Yes, internal growth only applies to increasing output", "No, but only ''internal growth'' should be used in exam answers"]}'::jsonb, '{"answer": 0, "explain": "Organic growth and internal growth are the same thing and are fully interchangeable terms in the exam."}'::jsonb),
('business:1-6-business-growth:misc:215e5c9b', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For evaluation questions, students list pros and cons but never commit to a final decision.</p><p><strong>✅ The correct idea:</strong> An evaluation MUST end with a clear, justified decision — ''I recommend X because...''. Sitting on the fence scores zero evaluation marks no matter how good the analysis is. The examiner needs to see a decision AND a contextual justification.</p>", "question": "What is required for an evaluation answer to score full evaluation marks?", "options": ["A clear, justified final decision, not just a list of pros and cons", "A minimum of six advantages and disadvantages", "Avoiding any mention of the case study business by name", "A list of pros and cons without picking a side, to stay balanced"]}'::jsonb, '{"answer": 0, "explain": "Sitting on the fence scores zero evaluation marks — a clear decision with contextual justification is required, no matter how strong the analysis is."}'::jsonb),
('business:1-6-business-growth:tips:d6073d32', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1 mark — One Specific Term. Full Stop. Move On.", "reading": "<p>A 1-mark <strong>''Identify''</strong> question needs exactly one correct, specific answer. Do not waste time writing a sentence or definition.</p>\n    <p><strong>The Formula: One precise term = 1 mark ✅</strong></p>\n    <ul>\n      <li><strong>✅ Good Answer:</strong> <em>\"Merger\"</em> or <em>\"Horizontal takeover\"</em></li>\n      <li><strong>❌ Bad Answer:</strong> <em>\"The business grew by joining with another company.\"</em> — Too vague. Name the specific term.</li>\n    </ul>\n    <p><strong>⚠️ Examiner Warning (Q2i — Nina''s Knitting Supplies):</strong></p>\n    <p>The examiner noted this question \"dichotomised candidates\" — students either knew the terms for external growth and scored full marks, or didn''t and scored zero. This is a pure <strong>vocabulary test</strong>. Revise these terms: merger, takeover, horizontal, backward/forward vertical, diversification.</p>\n    <p><strong>🚫 Don''t confuse organic and external growth methods.</strong> ''Developing new products'' is organic. ''Merger'' is external. The question will always specify which type it wants.</p>", "question": "What is the correct approach to answering a 1-mark ''Identify'' question?", "options": ["Give one precise, specific term without explanation", "Write a full sentence defining the term", "List as many relevant terms as possible", "Explain the advantages and disadvantages of the term"]}'::jsonb, '{"answer": 0, "explain": "The formula for a 1-mark Identify question is one precise term = 1 mark — writing a vague sentence instead of naming the specific term (e.g. ''merger'') loses the mark."}'::jsonb),
('business:1-6-business-growth:tips:c67b48e9', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — State It + Apply It to the Business", "reading": "<p>A 2-mark <strong>''Explain''</strong> question needs a point AND a development linked to the specific business in the case study.</p>\n    <p><strong>The Formula: State the method (1 mark) + Apply to the business context (1 mark)</strong></p>\n    <ul>\n      <li><strong>Step 1 — State:</strong> Name the specific method of organic/external growth.</li>\n      <li><strong>Step 2 — Apply:</strong> Link it directly to the business using a detail from the case study.</li>\n    </ul>\n    <p><strong>✅ Good Answer — Boohoo (2 marks):</strong></p>\n    <p><em>\"Boohoo may have expanded organically by gaining new customers (1) through using social media platforms such as Instagram and Facebook to target its 16–24 year old fashion-conscious market (1).\"</em></p>\n    <p><strong>❌ Bad Answer (0–1 marks):</strong></p>\n    <p><em>\"Boohoo grew by selling more things.\"</em> — Too vague, no context, scores 0 or 1 at most.</p>\n    <p><strong>🚫 Don''t just define organic growth.</strong> The question asks HOW the specific business used it. Use a case study detail to prove you understand the application.</p>", "question": "What must a 2-mark ''Explain'' answer include to score both marks?", "options": ["A stated method plus its application to the business", "Two different named methods with no further detail", "A definition of organic growth only", "A comparison between two different businesses"]}'::jsonb, '{"answer": 0, "explain": "The formula for 2-mark Explain questions is: state the method (1 mark) plus apply it to the business context using a case study detail (1 mark)."}'::jsonb),
('business:1-6-business-growth:tips:66733aaa', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "<p>The 3-mark analyse question requires a precise three-step chain. <strong>You will score zero for analysis if you don''t apply it to the specific business in the case study.</strong></p>\n    <p><strong>The 3-Step Formula:</strong></p>\n    <ul>\n      <li><strong>Step 1 — Understanding (U):</strong> State the benefit or drawback clearly. e.g., \"Merging with a flour producer could reduce raw material costs.\"</li>\n      <li><strong>Step 2 — Application (APP):</strong> Quote or reference a specific detail from the case study. e.g., \"...as flour is a key ingredient in Greggs&apos pastries and sausage rolls.\"</li>\n      <li><strong>Step 3 — Analysis (AN):</strong> State the bottom-line business impact. e.g., \"This would allow Greggs to lower retail prices, increasing sales.\"</li>\n    </ul>\n    <p><strong>The \"So What?\" Rule:</strong> Keep asking \"So what?\" until you reach a real business impact on costs, revenue, profit, market share, or cash flow.</p>\n    <p><strong>✅ Full-mark Answer (Greggs, 3 marks):</strong><br/>\n    <em>\"Merging with a flour producer could reduce raw material costs (U), as flour is a key ingredient in Greggs&apos pastries and vegan sausage rolls (APP). This would allow Greggs to lower its retail prices, increasing sales and helping it achieve its aim of being the nation''s favourite food-on-the-go provider (AN).\"</em></p>\n    <p><strong>❌ Bad Answer (1 mark max):</strong><br/>\n    <em>\"It would reduce costs and increase profit.\"</em> — No application, no chain = 1 mark at best.</p>", "question": "According to the ''Holy Trinity'' formula for a 3-mark Analyse question, what three steps must the answer contain?", "options": ["Understanding, Application, Analysis", "Knowledge, Understanding, Evaluation", "Definition, Example, Conclusion", "Advantage, Disadvantage, Decision"]}'::jsonb, '{"answer": 0, "explain": "The three-step chain is Understanding (state the benefit/drawback), Application (a case study detail), and Analysis (the bottom-line business impact) — missing the application step scores zero for analysis."}'::jsonb),
('business:1-6-business-growth:tips:81bf466a', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tips', 'mcq', 1, '{"readingTitle": "Analyse Two — 6 marks — Do the 3-Mark Formula Twice", "reading": "<p>A 6-mark ''Analyse two...'' question is a 3-mark question done <strong>twice</strong>. Write two clearly separate, labelled paragraphs.</p>\n    <p><strong>Structure:</strong></p>\n    <ul>\n      <li><strong>Benefit 1:</strong> U → APP → AN (3 marks)</li>\n      <li><strong>Benefit 2:</strong> U → APP → AN (3 marks)</li>\n    </ul>\n    <p><strong>⚠️ Examiner Warning (Beautiful Buds Q8a):</strong></p>\n    <p>The examiner noted that many students jumped straight to \"more profit\" with no link to external growth. This scores zero. You must build the chain: <em>\"Merging (U) gives Beautiful Buds access to Green Gardens'' 12% market share (APP), increasing its sales revenue from selling plants through their retail outlets (AN).\"</em></p>\n    <p><strong>🚫 Do NOT write a conclusion.</strong> There are zero evaluation marks available in a 6-mark question. A conclusion wastes time.</p>\n    <p><strong>Context tip (Beautiful Buds):</strong> Contextual references include plants, garden centres, 12% market share, country''s largest retailer. Use them! ''Managers'' or ''Leaders'' alone are too vague for application marks.</p>", "question": "Why should a student NOT write a conclusion in a 6-mark ''Analyse two...'' question?", "options": ["Because zero evaluation marks are available, wasting time", "Because conclusions are only allowed in 1-mark questions", "Because the question only allows one paragraph in total", "Because a conclusion would repeat the case study title"]}'::jsonb, '{"answer": 0, "explain": "The card explicitly warns not to write a conclusion because a 6-mark Analyse question carries zero evaluation marks, making a conclusion a waste of exam time."}'::jsonb),
('business:1-6-business-growth:tips:64fb50ea', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 7 marks — Four-Paragraph Structure for Full Marks", "reading": "<p>A 7-mark evaluate question tests all four skills. Use this four-paragraph structure:</p>\n    <ul>\n      <li><strong>Paragraph 1 — K & U:</strong> State and briefly define an advantage of the strategy.</li>\n      <li><strong>Paragraph 2 — AN & APP:</strong> Build a contextual chain: U → APP (case study detail) → AN (business impact).</li>\n      <li><strong>Paragraph 3 — AN & APP:</strong> Repeat for a disadvantage or the alternative method.</li>\n      <li><strong>Paragraph 4 — Evaluation (3 points):</strong> Decision + Contextual justification + Impact/reasoning.</li>\n    </ul>\n    <p><strong>Evaluation sentence starters:</strong></p>\n    <ul>\n      <li><em>\"Overall, I believe [business] should [action] because...\"</em> — Decision (1 mark)</li>\n      <li><em>\"This is particularly important because the case study states that...\"</em> — Context (+1 mark)</li>\n      <li><em>\"Therefore, this approach would [specific business impact], meaning...\"</em> — Reasoning (+1 mark)</li>\n    </ul>\n    <p><strong>⚠️ \"Sitting on the fence\" = 0 evaluation marks.</strong> You MUST make a clear decision. The \"It depends on...\" construction is only valid if you then commit to which side that condition favours.</p>\n    <p><strong>Exemplar from Nina''s Knitting Supplies (full marks):</strong><br/>\n    <em>\"I think Nina should switch to external growth. A merger with a competitor knitting retailer (CONT) would help her grow market share faster than organic growth, which she has done for 15 years already (EVAL). This is especially important now that new competitors are entering the market, meaning organic growth alone may no longer be fast enough to protect her business (EVAL).\"</em></p>", "question": "What happens if a student''s evaluation answer ''sits on the fence'' without making a decision?", "options": ["It scores zero evaluation marks, whatever the analysis", "It automatically scores half marks", "It is acceptable as long as both sides are equally detailed", "It only loses the Knowledge and Understanding marks"]}'::jsonb, '{"answer": 0, "explain": "The card states clearly that ''sitting on the fence'' equals 0 evaluation marks — a clear, justified decision is required for those marks."}'::jsonb),
('business:1-6-business-growth:tips:3c224355', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate with Data — 9 marks — Use the Numbers — They''re Worth 2 Free Marks", "reading": "<p>The 9-mark question awards <strong>2 separate marks purely for using numerical data</strong>. This is the most commonly missed opportunity on the entire paper.</p>\n    <p><strong>What counts as quantitative application (Shinz Ltd example):</strong></p>\n    <ul>\n      <li>Combined market share: \"40% + 10% = 50% combined market share\"</li>\n      <li>Market value: \"50% of £460,000 = £230,000\"</li>\n      <li>Share change: \"Shinz''s market share rose by 25 percentage points in 3 years\"</li>\n      <li>Customer satisfaction gap: \"Shinz''s satisfaction is 42 percentage points higher than Littlelong''s\"</li>\n      <li>Post-merger ownership: \"The business would have 5 owners\"</li>\n    </ul>\n    <p><strong>The 9-mark structure:</strong></p>\n    <ul>\n      <li><strong>K (1 mark):</strong> Define what a merger is OR use merger terminology (horizontal, vertical, etc.)</li>\n      <li><strong>U (1 mark):</strong> State one advantage or disadvantage</li>\n      <li><strong>APP (2 marks):</strong> Two uses of numerical data from the case study</li>\n      <li><strong>AN (2 marks):</strong> Two business-facing impacts</li>\n      <li><strong>EVAL (3 marks):</strong> Justified contextual decision</li>\n    </ul>\n    <p><strong>⚠️ Examiner Warning (Shinz Q3):</strong> Many high-ability students lost the Knowledge mark by not explicitly defining a merger or using merger terminology. Don''t assume the examiner knows you know the definition — say it in your first sentence!</p>", "question": "In a 9-mark ''Evaluate with Data'' question, how many marks are specifically available just for using numerical data from the case study?", "options": ["2 marks", "0 marks — data use is not separately credited", "5 marks", "1 mark"]}'::jsonb, '{"answer": 0, "explain": "The card states the 9-mark question awards 2 separate marks purely for quantitative/numerical application, calling it ''the most commonly missed opportunity on the entire paper''."}'::jsonb),
('business:1-6-business-growth:tips:1d70f7bd', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tips', 'mcq', 1, '{"readingTitle": "Recommend — 3 marks — Compare the Two Options — Don''t Just Praise One", "reading": "<p>A 3-mark ''Recommend'' question (like Greggs Q4iii) needs a decision AND a <em>comparative</em> justification.</p>\n    <p><strong>The Formula:</strong></p>\n    <ul>\n      <li><strong>Decision (1 mark):</strong> A clear choice — name the specific method you recommend.</li>\n      <li><strong>Non-contextual comparison (1 mark):</strong> Explain why your choice is BETTER THAN the other option (no case study detail needed).</li>\n      <li><strong>Contextual comparison (2 marks):</strong> Explain why your choice is better using specific details from the case study.</li>\n    </ul>\n    <p><strong>Key rule: The justification MUST be comparative.</strong> Simply listing advantages of your chosen option without mentioning the other gets no justification marks. Look for comparator words: <em>whereas, unlike, compared to, better than, although.</em></p>\n    <p><strong>✅ Full-mark Answer (Greggs):</strong><br/>\n    <em>\"Greggs should merge with the flour producer (1) because it allows the business to quality-assure one of the main ingredients it needs for its vegan pastries (CONT), whereas a takeover of a rival would only put more pressure on management capacity and supply of ingredients (+2).\"</em></p>\n    <p><strong>❌ Bad Answer (1 mark only):</strong><br/>\n    <em>\"Greggs should take over a competitor because it will increase market share.\"</em> — No comparison, no context. 1 mark maximum.</p>", "question": "What is the key rule for the justification in a 3-mark ''Recommend'' question?", "options": ["The justification must compare the choice to the alternative", "The justification only needs to list advantages of the chosen option", "The justification must avoid mentioning the case study business", "The justification must include a numerical calculation"]}'::jsonb, '{"answer": 0, "explain": "The justification MUST be comparative — simply listing advantages of the chosen option without comparing it to the other option gets no justification marks."}'::jsonb),
